import React from 'react';
import GlassCard from '../components/GlassCard';

/**
 * Products page placeholder
 * Will be enhanced in later tasks with actual product functionality
 */
const Products = () => {
  return (
    <div className="pt-24 pb-16">
      <div className="max-w-6xl mx-auto px-4">
        <GlassCard className="p-8 text-center mb-8">
          <h1 className="text-gray-800 mb-4">Our Products</h1>
          <p className="text-gray-600">
            Browse our comprehensive selection of medications, supplements, and healthcare products.
          </p>
        </GlassCard>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {/* Placeholder product cards */}
          {[1, 2, 3, 4, 5, 6].map((item) => (
            <GlassCard key={item} className="p-6" hover>
              <div className="aspect-square bg-gradient-to-br from-glass-blue/20 to-glass-green/20 rounded-lg mb-4 flex items-center justify-center">
                <span className="text-gray-500">Product Image</span>
              </div>
              <h3 className="text-gray-800 mb-2">Product Name {item}</h3>
              <p className="text-gray-600 mb-4">Product description and details will be displayed here.</p>
              <div className="flex justify-between items-center">
                <span className="text-lg font-semibold text-gray-800">$XX.XX</span>
                <button className="glass-button-primary">Add to Cart</button>
              </div>
            </GlassCard>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Products;
